"use client"

import type { ReactElement, ReactNode } from "react"
import type {
  GenericsComponent,
  ThemeProps,
  WithoutThemeProps,
} from "@yamada-ui/react"
import type { GroupProps } from "../group"
import type { UseInputBorderProps } from "../input"
import type { CheckboxProps } from "./checkbox"
import type { CheckboxStyle } from "./checkbox.style"
import type { UseCheckboxGroupProps } from "./use-checkbox-group"
import { useMemo } from "react"
import { Group } from "../group"
import {
  Checkbox,
  CheckboxPropsContext,
  component,
  useRootComponentProps,
} from "./checkbox"
import { CheckboxGroupContext, useCheckboxGroup } from "./use-checkbox-group"

export interface CheckboxGroupItem<
  Y extends string = string,
> extends CheckboxProps<Y> {
  label: ReactNode
}

export interface CheckboxGroupRootProps<Y extends string = string>
  extends
    Omit<
      WithoutThemeProps<GroupProps, CheckboxStyle>,
      "defaultValue" | "onChange" | "value"
    >,
    ThemeProps<CheckboxStyle>,
    UseCheckboxGroupProps<Y>,
    UseInputBorderProps,
    Pick<CheckboxProps, "checkedIcon"> {
  /**
   * If provided, generate options based on items.
   *
   * @default []
   */
  items?: CheckboxGroupItem<Y>[]
}

/**
 * `CheckboxGroup` is a component that groups `Checkbox` components.
 *
 * @see https://yamada-ui.com/docs/components/checkbox
 */
export const CheckboxGroupRoot = component<"div", CheckboxGroupRootProps>(
  (props) => {
    const [
      ,
      {
        colorScheme,
        size,
        variant,
        checkedIcon,
        children,
        disabled,
        errorBorderColor,
        focusBorderColor,
        invalid,
        items = [],
        readOnly,
        shape,
        ...rest
      },
    ] = useRootComponentProps(props, "group", {
      transferProps: ["variant", "colorScheme", "size", "shape"],
    })
    const { max, value, getInputProps, getLabelProps, getRootProps, onChange } =
      useCheckboxGroup(rest)
    const computedChildren = useMemo(() => {
      if (children) return children

      return items.map(({ label, value, ...rest }, index) => (
        <Checkbox key={value ?? index} value={value} {...rest}>
          {label}
        </Checkbox>
      ))
    }, [items, children])
    const context = useMemo(
      () => ({
        colorScheme,
        size,
        variant,
        checkedIcon,
        disabled,
        errorBorderColor,
        focusBorderColor,
        invalid,
        readOnly,
        shape,
      }),
      [
        variant,
        size,
        colorScheme,
        shape,
        disabled,
        invalid,
        readOnly,
        errorBorderColor,
        focusBorderColor,
        checkedIcon,
      ],
    )
    const groupContext = useMemo(
      () => ({ max, value, getInputProps, getLabelProps, onChange }),
      [max, value, getInputProps, getLabelProps, onChange],
    )

    return (
      <CheckboxPropsContext value={context}>
        <CheckboxGroupContext value={groupContext}>
          <Group orientation="vertical" {...getRootProps()}>
            {computedChildren}
          </Group>
        </CheckboxGroupContext>
      </CheckboxPropsContext>
    )
  },
  "group",
)() as GenericsComponent<{
  <Y extends string = string>(props: CheckboxGroupRootProps<Y>): ReactElement
}>

export { Checkbox as CheckboxGroupItem }

import { defineComponentSlotStyle, focusRingStyle } from "@yamada-ui/react"

export const checkboxStyle = defineComponentSlotStyle({
  base: {
    group: {},
    indicator: {
      alignItems: "center",
      bg: "{indicator-bg}",
      borderColor: "{indicator-border-color}",
      borderWidth: "2px",
      boxSize: "{indicator-size}",
      display: "inline-flex",
      focusRingColor: "{focus-border-color}",
      "input:focus-visible + &": focusRingStyle.outline,
      justifyContent: "center",
      _container: [
        { css: { bg: "bg" }, style: '--form-group-variant: "panel"' },
        { css: { bg: "bg" }, style: '--fieldset-root-variant: "panel"' },
        { css: { bg: "bg" }, style: '--form-group-variant: "elevated"' },
        { css: { bg: "bg" }, style: '--fieldset-root-variant: "elevated"' },
      ],
      _invalid: {
        borderColor: "{error-border-color}",
        focusRingColor: "{error-border-color}",
      },
    },
    label: {},
    root: {
      "--error-border-color": "colors.border.error",
      "--focus-border-color": "colorScheme.outline",
      "--indicator-bg": "transparent",
      "--indicator-border-color": "colors.border.emphasized",
      alignItems: "center",
      display: "flex",
      fontSize: "{label-size}",
      gap: "2",
      userSelect: "none",
      _readOnly: { layerStyle: "readOnly" },
      _disabled: { layerStyle: "disabled" },
    },
  },

  props: {
    /**
     * The shape of the component
     *
     * @default 'rounded'
     */
    shape: {
      rounded: {
        indicator: { rounded: "l1" },
      },
      square: {
        indicator: { rounded: "0" },
      },
    },
  },

  variants: {
    outline: {
      indicator: { color: "colorScheme.outline" },
      root: {
        _checked: { "--indicator-border-color": "colorScheme.outline" },
        _indeterminate: { "--indicator-border-color": "colorScheme.outline" },
      },
    },
    solid: {
      indicator: {
        color: "colorScheme.contrast",
        _checked: { bg: "colorScheme.solid" },
        _indeterminate: { bg: "colorScheme.solid" },
      },
      root: {
        _checked: { "--indicator-border-color": "colorScheme.solid" },
        _indeterminate: { "--indicator-border-color": "colorScheme.solid" },
      },
    },
    subtle: {
      indicator: { bg: "colorScheme.subtle", color: "colorScheme.fg" },
      root: { "--indicator-border-color": "transparent" },
    },
    surface: {
      indicator: { bg: "colorScheme.subtle", color: "colorScheme.fg" },
      root: { "--indicator-border-color": "colorScheme.muted" },
    },
  },

  sizes: {
    sm: {
      indicator: { fontSize: "xs" },
      root: { "--indicator-size": "sizes.3.5", "--label-size": "fontSizes.sm" },
    },
    md: {
      indicator: { fontSize: "sm" },
      root: { "--indicator-size": "sizes.4", "--label-size": "fontSizes.md" },
    },
    lg: {
      indicator: { fontSize: "md" },
      root: { "--indicator-size": "sizes.5", "--label-size": "fontSizes.lg" },
    },
  },

  defaultProps: {
    size: "md",
    variant: "solid",
    shape: "rounded",
  },
})

export type CheckboxStyle = typeof checkboxStyle

import { a11y, fireEvent, page, render, renderHook } from "#test/browser"
import { CheckboxGroup } from "."
import { Checkbox } from "./checkbox"
import { useCheckbox } from "./use-checkbox"
import { useCheckboxGroup } from "./use-checkbox-group"

const items = [
  { label: "Item 1", value: "1" },
  { label: "Item 2", value: "2" },
  { label: "Item 3", value: "3" },
]

describe("<Checkbox />", () => {
  test("renders component correctly", async () => {
    await a11y(<Checkbox defaultChecked>checkbox</Checkbox>)
  })

  test("sets `aria-checked` to mixed and native `indeterminate` when indeterminate", async () => {
    await render(<Checkbox indeterminate>checkbox</Checkbox>)

    const input = page.getByRole("checkbox").element()

    expect(input).toHaveAttribute("aria-checked", "mixed")
    expect((input as HTMLInputElement).indeterminate).toBeTruthy()
  })

  test("forwards `aria-controls` to the input element", async () => {
    await render(<Checkbox aria-controls="panel1">checkbox</Checkbox>)

    const input = page.getByRole("checkbox").element()

    expect(input).toHaveAttribute("aria-controls", "panel1")
  })

  test("forwards `aria-labelledby` to the input element", async () => {
    await render(<Checkbox aria-labelledby="label1">checkbox</Checkbox>)

    const input = page.getByRole("checkbox").element()

    expect(input).toHaveAttribute("aria-labelledby", "label1")
  })

  test("forwards `tabIndex` to the input element", async () => {
    await render(<Checkbox tabIndex={-1}>checkbox</Checkbox>)

    const input = page.getByRole("checkbox").element()

    expect(input).toHaveAttribute("tabindex", "-1")
  })

  test("sets `displayName` correctly", () => {
    expect(Checkbox.displayName).toBe("CheckboxRoot")
    expect(CheckboxGroup.Root.displayName).toBe("CheckboxGroup")
  })

  test("sets `className` correctly", async () => {
    await render(<CheckboxGroup.Root items={items} />)
    const checkbox = page.getByRole("checkbox").elements()[0]
    expect(page.getByRole("group").element()).toHaveClass("ui-checkbox__group")
    expect(checkbox?.parentElement).toHaveClass("ui-checkbox__root")
    expect(checkbox?.parentElement?.children[1]).toHaveClass(
      "ui-checkbox__indicator",
    )
    expect(checkbox?.parentElement?.children[2]).toHaveClass(
      "ui-checkbox__label",
    )
  })

  test("renders HTML tag correctly", async () => {
    await render(<CheckboxGroup.Root items={items} />)
    const checkbox = page.getByRole("checkbox").elements()[0]
    expect(page.getByRole("group").element().tagName).toBe("DIV")
    expect(checkbox?.parentElement?.tagName).toBe("LABEL")
    expect(checkbox?.tagName).toBe("INPUT")
    expect(checkbox?.parentElement?.children[1]?.tagName).toBe("DIV")
    expect(checkbox?.parentElement?.children[2]?.tagName).toBe("SPAN")
  })

  test("merges root props on Checkbox without overwriting className, style, or ref", async () => {
    const userRef = vi.fn()
    await render(
      <Checkbox
        className="from-root"
        rootProps={{
          ref: userRef,
          className: "from-user",
          style: { backgroundColor: "blue", color: "red" },
          "data-testid": "checkbox-root",
        }}
      >
        checkbox
      </Checkbox>,
    )

    const root = page.getByTestId("checkbox-root")

    await expect.element(root).toHaveClass("ui-checkbox__root")
    await expect.element(root).toHaveClass("from-root")
    await expect.element(root).toHaveClass("from-user")
    await expect.element(root).toHaveStyle({ color: "rgb(255, 0, 0)" })
    await expect
      .element(root)
      .toHaveStyle({ backgroundColor: "rgb(0, 0, 255)" })
    expect(userRef).toHaveBeenCalledTimes(1)
    expect(userRef).toHaveBeenCalledWith(root.element())
  })

  test("merges root props values in useCheckbox with caller props", async () => {
    const restOnClick = vi.fn()
    const callerOnClick = vi.fn()
    const { result } = await renderHook(() =>
      useCheckbox({
        className: "from-rest",
        style: { backgroundColor: "red", paddingTop: "4px" },
        onClick: restOnClick,
      }),
    )

    const rootProps = result.current.getRootProps({
      className: "from-caller",
      style: { color: "blue", paddingTop: "8px" },
      onClick: callerOnClick,
    })

    expect(rootProps.className).toContain("from-rest")
    expect(rootProps.className).toContain("from-caller")
    expect(rootProps.style).toMatchObject({
      backgroundColor: "red",
      color: "blue",
      paddingTop: "8px",
    })

    rootProps.onClick?.({} as any)

    expect(restOnClick).toHaveBeenCalledTimes(1)
    expect(callerOnClick).toHaveBeenCalledTimes(1)
  })
})

describe("<CheckboxGroup />", () => {
  test("should handle onChange callback when checking checkboxes", async () => {
    const onChange = vi.fn()
    await render(<CheckboxGroup.Root items={items} onChange={onChange} />)

    const checkboxes = page.getByRole("checkbox").elements()

    fireEvent.click(checkboxes[0]!)
    expect(onChange).toHaveBeenCalledTimes(1)
    expect(onChange).toHaveBeenLastCalledWith(["1"])

    fireEvent.click(checkboxes[1]!)
    expect(onChange).toHaveBeenCalledTimes(2)
    expect(onChange).toHaveBeenLastCalledWith(["1", "2"])
  })

  test("should remove value when unchecking checkbox", async () => {
    const onChange = vi.fn()
    await render(
      <CheckboxGroup.Root
        defaultValue={["1", "2"]}
        items={items}
        onChange={onChange}
      />,
    )

    const checkboxes = page.getByRole("checkbox").elements()

    expect(checkboxes[0]).toBeChecked()
    expect(checkboxes[1]).toBeChecked()

    fireEvent.click(checkboxes[0]!)
    expect(onChange).toHaveBeenCalledTimes(1)
    expect(onChange).toHaveBeenLastCalledWith(["2"])

    fireEvent.click(checkboxes[1]!)
    expect(onChange).toHaveBeenCalledTimes(2)
    expect(onChange).toHaveBeenLastCalledWith([])
  })

  test("should respect max limit when checking checkboxes", async () => {
    const onChange = vi.fn()
    await render(
      <CheckboxGroup.Root items={items} max={2} onChange={onChange} />,
    )

    const checkboxes = page.getByRole("checkbox").elements()

    fireEvent.click(checkboxes[0]!)
    expect(onChange).toHaveBeenLastCalledWith(["1"])

    fireEvent.click(checkboxes[1]!)
    expect(onChange).toHaveBeenLastCalledWith(["1", "2"])

    fireEvent.click(checkboxes[2]!)
    expect(onChange).toHaveBeenCalledTimes(2)
    expect(onChange).not.toHaveBeenLastCalledWith(["1", "2", "3"])
  })

  test("should disable unchecked checkboxes when max limit is reached", async () => {
    await render(
      <CheckboxGroup.Root defaultValue={["1", "2"]} items={items} max={2} />,
    )

    const checkboxes = page.getByRole("checkbox").elements()

    expect(checkboxes[0]).toBeChecked()
    expect(checkboxes[1]).toBeChecked()
    expect(checkboxes[2]).not.toBeChecked()
    expect(checkboxes[2]).toHaveAttribute("aria-disabled", "true")
  })

  test("should enable disabled checkbox when value is removed", async () => {
    const { rerender } = await render(
      <CheckboxGroup.Root items={items} max={2} value={["1", "2"]} />,
    )

    const checkboxes = page.getByRole("checkbox").elements()

    expect(checkboxes[2]).toHaveAttribute("aria-disabled", "true")

    await rerender(<CheckboxGroup.Root items={items} max={2} value={["1"]} />)

    expect(checkboxes[2]).not.toHaveAttribute("aria-disabled", "true")
  })

  test("should prevent clicks when disabled checkboxes due to max limit", async () => {
    const onChange = vi.fn()
    await render(
      <CheckboxGroup.Root
        defaultValue={["1", "2"]}
        items={items}
        max={2}
        onChange={onChange}
      />,
    )

    const checkboxes = page.getByRole("checkbox")

    await expect.element(checkboxes.nth(2)).toBeDisabled()
    fireEvent.click(checkboxes.nth(2).element())
    expect(onChange).not.toHaveBeenCalled()
  })

  test("should not change value when readOnly", async () => {
    const onChange = vi.fn()
    await render(
      <CheckboxGroup.Root items={items} readOnly onChange={onChange} />,
    )

    const checkboxes = page.getByRole("checkbox").elements()

    fireEvent.click(checkboxes[0]!)
    expect(onChange).not.toHaveBeenCalled()
  })

  test("should handle defaultValue correctly", async () => {
    await render(<CheckboxGroup.Root defaultValue={["1", "3"]} items={items} />)

    const checkboxes = page.getByRole("checkbox").elements()

    expect(checkboxes[0]).toBeChecked()
    expect(checkboxes[1]).not.toBeChecked()
    expect(checkboxes[2]).toBeChecked()
  })

  test("should handle controlled value correctly", async () => {
    const { rerender } = await render(
      <CheckboxGroup.Root items={items} value={["1"]} />,
    )

    const checkboxes = page.getByRole("checkbox").elements()

    expect(checkboxes[0]).toBeChecked()
    expect(checkboxes[1]).not.toBeChecked()

    await rerender(<CheckboxGroup.Root items={items} value={["1", "2"]} />)

    expect(checkboxes[0]).toBeChecked()
    expect(checkboxes[1]).toBeChecked()
  })

  test("should accept required prop", async () => {
    // Note: Currently, the required prop on CheckboxGroup doesn't propagate
    // as observable attributes (required/aria-required/data-required) on checkbox inputs.
    // This test verifies the component accepts the prop without error.
    // Ideally, we would assert: checkboxes have required/aria-required attributes.
    const { container } = await render(
      <CheckboxGroup.Root items={items} required />,
    )

    const group = container.querySelector('[role="group"]')
    const checkboxes = page.getByRole("checkbox").elements()

    expect(group).toBeInTheDocument()
    expect(checkboxes).toHaveLength(items.length)
  })

  test("should not add value when max is reached via onChange", async () => {
    const { act, result } = await renderHook(() => useCheckboxGroup({ max: 1 }))

    await act(() => {
      result.current.onChange("1")
    })
    expect(result.current.value).toStrictEqual(["1"])

    await act(() => {
      result.current.onChange("2")
    })
    expect(result.current.value).toStrictEqual(["1"])
  })

  test("merges getRootProps values in useCheckboxGroup and calls each ref once", async () => {
    const restOnClick = vi.fn()
    const callerOnClick = vi.fn()
    const restRef = vi.fn()
    const callerRef = vi.fn()
    const rootElement = document.createElement("div")
    const { result } = await renderHook(() =>
      useCheckboxGroup({
        ref: restRef,
        className: "from-rest",
        style: { backgroundColor: "red", paddingTop: "4px" },
        onClick: restOnClick,
      }),
    )

    const rootProps = result.current.getRootProps({
      ref: callerRef,
      className: "from-caller",
      style: { color: "blue", paddingTop: "8px" },
      onClick: callerOnClick,
    })

    expect(rootProps.className).toContain("from-rest")
    expect(rootProps.className).toContain("from-caller")
    expect(rootProps.style).toMatchObject({
      backgroundColor: "red",
      color: "blue",
      paddingTop: "8px",
    })
    expect(rootProps.role).toBe("group")

    rootProps.onClick?.({} as any)
    if (typeof rootProps.ref === "function") rootProps.ref(rootElement)

    expect(restOnClick).toHaveBeenCalledTimes(1)
    expect(callerOnClick).toHaveBeenCalledTimes(1)
    expect(restRef).toHaveBeenCalledTimes(1)
    expect(callerRef).toHaveBeenCalledTimes(1)
    expect(restRef).toHaveBeenCalledWith(rootElement)
    expect(callerRef).toHaveBeenCalledWith(rootElement)
  })
})

"use client"

import type { ReactElement, ReactNode } from "react"
import type { GenericsComponent, HTMLStyledProps, ThemeProps, Merge } from "@yamada-ui/react"
import type { UseInputBorderProps } from "../input"
import type { CheckboxStyle } from "./checkbox.style"
import type { UseCheckboxProps } from "./use-checkbox"
import { useMemo } from "react"
import { createSlotComponent, styled } from "@yamada-ui/react"
import { CheckIcon, MinusIcon } from "../icon"
import { useInputBorder } from "../input"
import { checkboxStyle } from "./checkbox.style"
import { useCheckbox } from "./use-checkbox"

export interface CheckboxProps<Y extends string = string>
  extends
    Merge<HTMLStyledProps<"label">, UseCheckboxProps<Y>>,
    ThemeProps<CheckboxStyle>,
    UseInputBorderProps {
  /**
   * The icon to display in the checkbox when it is checked.
   */
  checkedIcon?: ReactNode
  /**
   * The icon to display in the checkbox when it is indeterminate.
   */
  indeterminateIcon?: ReactNode
  /**
   * Props for the indicator component.
   */
  indicatorProps?: CheckboxIndicatorProps
  /**
   * Props for the input element.
   */
  inputProps?: HTMLStyledProps<"input">
  /**
   * Props for the label component.
   */
  labelProps?: CheckboxLabelProps
  /**
   * Props for the label element.
   */
  rootProps?: HTMLStyledProps<"label">
}

const {
  component,
  PropsContext: CheckboxPropsContext,
  usePropsContext: useCheckboxPropsContext,
  withContext,
  withProvider,
  useRootComponentProps,
} = createSlotComponent<CheckboxProps, CheckboxStyle>("checkbox", checkboxStyle)

export {
  CheckboxPropsContext,
  component,
  useCheckboxPropsContext,
  useRootComponentProps,
}

/**
 * `Checkbox` is a component used for allowing users to select multiple values from multiple options.
 *
 * @see https://yamada-ui.com/docs/components/checkbox
 */
export const Checkbox = withProvider<"label", CheckboxProps>(
  ({
    checkedIcon,
    children,
    errorBorderColor,
    focusBorderColor,
    indeterminateIcon,
    indicatorProps,
    inputProps,
    labelProps,
    rootProps,
    ...rest
  }) => {
    const {
      checked,
      indeterminate,
      getIndicatorProps,
      getInputProps,
      getRootProps,
    } = useCheckbox(rest)
    const varProps = useInputBorder({ errorBorderColor, focusBorderColor })
    const icon = useMemo(() => {
      if (indeterminate) {
        return indeterminateIcon || <MinusIcon />
      } else if (checked) {
        return checkedIcon || <CheckIcon />
      } else {
        return null
      }
    }, [indeterminate, indeterminateIcon, checked, checkedIcon])
    const input = useMemo(() => {
      return <styled.input {...getInputProps(inputProps)} />
    }, [getInputProps, inputProps])
    const indicator = useMemo(() => {
      return (
        <CheckboxIndicator {...getIndicatorProps(indicatorProps)}>
          {icon}
        </CheckboxIndicator>
      )
    }, [getIndicatorProps, indicatorProps, icon])

    return (
      <styled.label {...getRootProps({ ...varProps, ...rootProps })}>
        {input}
        {indicator}
        {children ? (
          <CheckboxLabel {...labelProps}>{children}</CheckboxLabel>
        ) : null}
      </styled.label>
    )
  },
  "root",
)() as GenericsComponent<{
  <Y extends string = string>(props: CheckboxProps<Y>): ReactElement
}>

interface CheckboxIndicatorProps extends HTMLStyledProps {}

const CheckboxIndicator = withContext<"div", CheckboxIndicatorProps>(
  "div",
  "indicator",
)({ "data-indicator": "" })

interface CheckboxLabelProps extends HTMLStyledProps<"span"> {}

const CheckboxLabel = withContext<"span", CheckboxLabelProps>("span", "label")()

export {
  CheckboxPropsContext as PropsContext,
  useCheckboxPropsContext as usePropsContext,
} from "./checkbox"
export type { CheckboxProps as ItemProps } from "./checkbox"
export {
  CheckboxGroupItem as Item,
  CheckboxGroupRoot as Root,
} from "./checkbox-group"
export type { CheckboxGroupRootProps as RootProps } from "./checkbox-group"

"use client"

import type { ChangeEvent } from "react"
import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import type { FieldProps } from "../field"
import { useCallback } from "react"
import {
  mergeProps,
  ariaAttr,
  createContext,
  cx,
  dataAttr,
  handlerAll,
  isNumber,
  isObject,
  isString,
  isUndefined,
  visuallyHiddenAttributes,
} from "@yamada-ui/react"
import { useControllableState } from "../../hooks/use-controllable-state"
import { useFieldProps } from "../field"

interface CheckboxGroupContext extends Omit<
  UseCheckboxGroupReturn,
  "getRootProps"
> {}

const [CheckboxGroupContext, useCheckboxGroupContext] =
  createContext<CheckboxGroupContext>({
    name: "CheckboxGroupContext",
    strict: false,
  })

export { CheckboxGroupContext, useCheckboxGroupContext }

export interface UseCheckboxGroupProps<Y extends string = string>
  extends Omit<HTMLProps, "defaultValue" | "onChange" | "value">, FieldProps {
  /**
   * The initial value of the checkbox group.
   *
   * @default []
   */
  defaultValue?: Y[]
  /**
   * The maximum number of checkboxes that can be checked.
   */
  max?: number
  /**
   * The value of the checkbox group.
   */
  value?: Y[]
  /**
   * The callback fired when any children checkbox is checked or unchecked.
   */
  onChange?: (value: Y[]) => void
}

export const useCheckboxGroup = <Y extends string = string>(
  props: UseCheckboxGroupProps<Y> = {},
) => {
  const {
    context: { labelId } = {},
    props: {
      defaultValue = [],
      disabled,
      max,
      readOnly,
      required,
      value: valueProp,
      onChange: onChangeProp,
      ...rest
    },
    ariaProps: { "aria-describedby": ariaDescribedbyProp, ...ariaProps },
    dataProps,
    eventProps,
  } = useFieldProps(props)
  const interactive = !(readOnly || disabled)
  const [value, setValue] = useControllableState({
    defaultValue,
    value: valueProp,
    onChange: onChangeProp,
  })

  const onChange = useCallback(
    (valueOrEv: ChangeEvent<HTMLInputElement> | Y) => {
      if (!interactive) return

      if (isObject(valueOrEv)) valueOrEv = valueOrEv.target.value as Y

      setValue((prev) => {
        if (prev.includes(valueOrEv)) {
          return prev.filter((prevValue) => prevValue !== valueOrEv)
        } else if (!isNumber(max) || prev.length < max) {
          return [...prev, valueOrEv]
        } else {
          return prev
        }
      })
    },
    [interactive, max, setValue],
  )

  const getRootProps: PropGetter = useCallback(
    ({
      ref,
      "aria-describedby": ariaDescribedby,
      "aria-labelledby": ariaLabelledby,
      ...props
    } = {}) =>
      mergeProps(
        dataProps,
        {
          "aria-describedby": cx(ariaDescribedbyProp, ariaDescribedby),
          "aria-labelledby": cx(labelId, ariaLabelledby),
          role: "group",
        },
        rest,
        props,
        {
          ref,
        },
      )(),
    [ariaDescribedbyProp, dataProps, labelId, rest],
  )

  const getInputProps: PropGetter<"input"> = useCallback(
    (props = {}) => {
      const checked =
        !isUndefined(value) &&
        (isString(props.value) || isNumber(props.value)) &&
        value.includes(props.value as Y)
      const trulyDisabled = !checked && isNumber(max) && value.length >= max

      return {
        ...dataProps,
        ...ariaProps,
        type: "checkbox",
        style: visuallyHiddenAttributes.style,
        "aria-checked": checked,
        "aria-disabled": ariaAttr(trulyDisabled),
        "data-checked": dataAttr(checked),
        "data-disabled": dataAttr(trulyDisabled),
        checked,
        disabled: trulyDisabled,
        readOnly,
        required,
        ...props,
        onBlur: handlerAll(props.onBlur, eventProps.onBlur),
        onChange: handlerAll(props.onChange, onChange),
        onFocus: handlerAll(props.onFocus, eventProps.onFocus),
      }
    },
    [
      ariaProps,
      dataProps,
      eventProps,
      max,
      onChange,
      readOnly,
      required,
      value,
    ],
  )

  const getLabelProps: PropGetter<"label"> = useCallback(
    (props) => ({
      ...dataProps,
      ...props,
    }),
    [dataProps],
  )

  return {
    max,
    value,
    getInputProps,
    getLabelProps,
    getRootProps,
    onChange,
  }
}

export type UseCheckboxGroupReturn = ReturnType<typeof useCheckboxGroup>
